parameters.jsCode:
const item = $input.first()?.json || {};

const created_at_iso = item.created_at_iso || new Date().toISOString();
const org_id = String(item.org_id || '').trim();
const platform = String(item.platform || '').trim();
const conversation_id = String(item.conversation_id || '').trim();
const run_token = `${Date.now()}:${$execution.id}`;

const buffer_key = `ai:gate:buffer:${org_id}:${platform}:${conversation_id}`;
const buffer_member_key = `${buffer_key}:${run_token}`;
const buffer_pattern = `${buffer_key}:*`;
const last_key = `ai:gate:last:${org_id}:${platform}:${conversation_id}`;
const drain_lock_key = `ai:gate:drain_lock:${org_id}:${platform}:${conversation_id}`;

const buffer_payload = JSON.stringify({
  message_id: item.id ?? null,
  org_id,
  platform,
  conversation_id,
  sender_external_id: item.sender_external_id ?? null,
  created_at_iso,
  content_type: item.content_type ?? null,
  provider_message_id: item.meta?.provider_message_id ?? item.provider_message_id ?? null
});

return [{
  json: {
    ...item,
    created_at_iso,
    buffer_key,
    buffer_member_key,
    buffer_pattern,
    last_key,
    drain_lock_key,
    run_token,
    buffer_payload,
  }
}];

const base = $('Validate Winner & Drain').first()?.json || {};
const current = $input.first()?.json || {};
const drainLockValue = current.drain_lock_value ?? null;

if (
  drainLockValue &&
  String(drainLockValue).trim() !== '' &&
  String(drainLockValue) !== String(base.run_token)
) {
  return [];
}

return [{
  json: {
    ...base,
    drain_lock_value: drainLockValue,
  }
}];

function safeJson(value, fallback = {}) {
  if (value && typeof value === 'object') return value;
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch (e) {
      return fallback;
    }
  }
  return fallback;
}

function cleanText(value) {
  return String(value ?? '').replace(/\s+/gu, ' ').trim();
}

function isLowSignalText(value) {
  const text = cleanText(value);
  if (!text) return true;
  if (/[\p{L}\p{N}]/u.test(text)) return false;
  return /^[\p{P}\p{S}\p{Z}\p{C}]+$/u.test(text);
}

function pushUnique(arr, value) {
  const text = cleanText(value);
  if (!text) return;
  if (!arr.includes(text)) arr.push(text);
}

const exact = $('Prepare Exact Buffered IDs').first()?.json || {};
const orderIds = Array.isArray(exact.current_burst_message_ids)
  ? exact.current_burst_message_ids.map((v) => String(v))
  : [];
const orderMap = new Map(orderIds.map((id, index) => [id, index]));

const rows = $input.all()
  .map((item) => item.json || {})
  .filter((row) => row && row.id !== undefined && row.id !== null);

rows.sort((a, b) => {
  const ai = orderMap.has(String(a.id)) ? orderMap.get(String(a.id)) : Number.MAX_SAFE_INTEGER;
  const bi = orderMap.has(String(b.id)) ? orderMap.get(String(b.id)) : Number.MAX_SAFE_INTEGER;
  if (ai !== bi) return ai - bi;
  const at = new Date(a.created_at || 0).getTime();
  const bt = new Date(b.created_at || 0).getTime();
  return at - bt;
});

const segments = [];
const burstImageSummaries = [];
const burstAudioTranscripts = [];
const burstContentTypes = [];
const burstProviderIds = [];

for (const row of rows) {
  const meta = safeJson(row.meta, {});
  const contentType = String(row.content_type ?? '').toLowerCase();
  const contentText = cleanText(row.content ?? row.content_text ?? '');

  if (contentType && !burstContentTypes.includes(contentType)) {
    burstContentTypes.push(contentType);
  }

  const providerId = meta.provider_message_id ?? row.provider_message_id ?? null;
  if (providerId) {
    const pid = String(providerId);
    if (!burstProviderIds.includes(pid)) burstProviderIds.push(pid);
  }

  if (contentType === 'text') {
    if (contentText) {
      segments.push({
        source_id: String(row.id),
        kind: 'text',
        text: contentText,
        lowSignal: isLowSignalText(contentText),
      });
    }
    continue;
  }

  if (contentType === 'audio') {
    const transcript = cleanText(meta.transcript ?? contentText);
    if (transcript) {
      pushUnique(burstAudioTranscripts, transcript);
      segments.push({
        source_id: String(row.id),
        kind: 'audio',
        text: transcript,
        lowSignal: isLowSignalText(transcript),
      });
    } else {
      segments.push({
        source_id: String(row.id),
        kind: 'audio',
        text: 'Customer sent a voice message.',
        lowSignal: false,
      });
    }
    continue;
  }

  if (contentType === 'image') {
    const imageAnalysis = safeJson(meta.image_analysis, {});
    const imageSummary = cleanText(
      meta.image_analysis_summary ??
      imageAnalysis.description ??
      ''
    );

    if (contentText) {
      segments.push({
        source_id: String(row.id),
        kind: 'image_caption',
        text: contentText,
        lowSignal: isLowSignalText(contentText),
      });
    }

    if (imageSummary) {
      pushUnique(burstImageSummaries, imageSummary);
      segments.push({
        source_id: String(row.id),
        kind: 'image_summary',
        text: imageSummary,
        lowSignal: false,
      });
    }

    if (!contentText && !imageSummary) {
      segments.push({
        source_id: String(row.id),
        kind: 'image',
        text: 'Customer sent an image.',
        lowSignal: false,
      });
    }
    continue;
  }

  if (contentText) {
    segments.push({
      source_id: String(row.id),
      kind: contentType || 'unknown',
      text: contentText,
      lowSignal: isLowSignalText(contentText),
    });
  }
}

const richSegments = segments.filter((segment) => !segment.lowSignal && cleanText(segment.text));
const fallbackSegments = segments.filter((segment) => cleanText(segment.text));
const selectedSegments = richSegments.length > 0 ? richSegments : fallbackSegments;
const buffered_input_text = selectedSegments.map((segment) => cleanText(segment.text)).join('\n').trim();

const latestRow = rows[rows.length - 1] || {};
const latestMeta = safeJson(latestRow.meta, {});

return [{
  json: {
    ...exact,
    buffered_input_text,
    current_burst_message_ids: orderIds,
    current_burst_provider_message_ids: burstProviderIds,
    burst_content_types: burstContentTypes,
    burst_has_image: burstContentTypes.includes('image'),
    burst_has_audio: burstContentTypes.includes('audio'),
    burst_primary_content_type: burstContentTypes[burstContentTypes.length - 1] ?? exact.burst_primary_content_type ?? latestRow.content_type ?? exact.content_type ?? null,
    burst_image_summaries: burstImageSummaries,
    burst_audio_transcripts: burstAudioTranscripts,
    current_burst_latest_inbox_message_id: latestRow.id ?? exact.id ?? null,
    current_burst_latest_content_type: latestRow.content_type ?? exact.content_type ?? null,
    current_burst_latest_meta: latestMeta,
  }
}];

const gate = $('Prepare Burst Keys').first()?.json || {};
const redisGet = $input.first()?.json || {};
const tokenFromRedis = redisGet.token_from_redis ?? null;

if (!gate.run_token || !tokenFromRedis || String(tokenFromRedis) !== String(gate.run_token)) {
  return [];
}

return [{
  json: {
    ...gate,
    token_from_redis: tokenFromRedis,
  }
}];

function safeJson(value, fallback = null) {
  if (value && typeof value === 'object') return value;
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch (e) {
      return fallback;
    }
  }
  return fallback;
}

const base = $('Prepare Burst Fetch').first()?.json || {};
const redisMap = $input.first()?.json || {};
const rawEntries = Object.entries(redisMap).filter(([key]) => key !== 'error');

const rawKeys = rawEntries.map(([key]) => key);

const parsed = [];
for (const [key, rawValue] of rawEntries) {
  const payload = safeJson(rawValue, null);
  if (!payload || typeof payload !== 'object') continue;

  const messageId = payload.message_id ?? payload.id ?? null;
  if (messageId === null || messageId === undefined || String(messageId).trim() === '') continue;

  if (payload.org_id && String(payload.org_id) !== String(base.org_id)) continue;
  if (payload.platform && String(payload.platform) !== String(base.platform)) continue;
  if (payload.conversation_id && String(payload.conversation_id) !== String(base.conversation_id)) continue;

  parsed.push({
    buffer_member_key: key,
    message_id: String(messageId),
    provider_message_id: payload.provider_message_id ? String(payload.provider_message_id) : null,
    content_type: payload.content_type ? String(payload.content_type).toLowerCase() : null,
    created_at_iso: payload.created_at_iso ? String(payload.created_at_iso) : null,
    sender_external_id: payload.sender_external_id ? String(payload.sender_external_id) : null,
  });
}

const seen = new Set();
const unique = parsed.filter((row) => {
  if (seen.has(row.message_id)) return false;
  seen.add(row.message_id);
  return true;
});

unique.sort((a, b) => {
  const at = new Date(a.created_at_iso || 0).getTime();
  const bt = new Date(b.created_at_iso || 0).getTime();
  if (at !== bt) return at - bt;
  return String(a.message_id).localeCompare(String(b.message_id));
});

const current_burst_message_ids = unique.map((row) => row.message_id);
const current_burst_provider_message_ids = [...new Set(unique.map((row) => row.provider_message_id).filter(Boolean))];
const burst_content_types = [...new Set(unique.map((row) => row.content_type).filter(Boolean))];

return [{
  json: {
    ...base,
    exact_buffer_payloads: unique,
    buffer_member_keys_to_cleanup: rawKeys,
    current_burst_message_ids,
    current_burst_provider_message_ids,
    burst_content_types,
    burst_has_image: burst_content_types.includes('image'),
    burst_has_audio: burst_content_types.includes('audio'),
    burst_primary_content_type: unique[unique.length - 1]?.content_type ?? base.content_type ?? null,
    buffered_item_count: unique.length,
    has_exact_buffered_ids: current_burst_message_ids.length > 0,
  }
}];

const base = $input.first()?.json || {};
const keys = Array.isArray(base.buffer_member_keys_to_cleanup)
  ? base.buffer_member_keys_to_cleanup.map((v) => String(v || '').trim()).filter(Boolean)
  : [];

return keys.map((cleanup_key) => ({
  json: {
    cleanup_key,
    drain_lock_key: base.drain_lock_key,
  }
}));

const inputRows = $input.all().map((item) => item.json || {});
const rows = inputRows.filter((row) => row && Object.keys(row).length > 0 && row.org_id !== undefined);
const source = ($('Extract Platform + External Account').all(0, $runIndex)[0] || {}).json || {};

if (rows.length !== 1) {
  return [
    {
      json: {
        auth_ok: false,
        error: 'tenant_not_unique_or_missing',
      },
    },
  ];
}

const row = rows[0];

return [
  {
    json: {
      auth_ok: true,
      org_id: row.org_id ?? null,
      platform: source.platform ?? row.platform ?? null,
      external_account_id: source.external_account_id ?? row.external_account_id ?? null,
      channel_access_token: row.access_token ?? '',
      channel_meta: row.meta || {},
      app_secret: row.meta?.app_secret || '',
      body: source.body || {},
      headers: source.headers || {},
      rawBodyString: typeof source.rawBodyString === 'string' ? source.rawBodyString : '',
      SUPABASE_URL: source.SUPABASE_URL || '',
      META_GRAPH_VERSION: source.META_GRAPH_VERSION || '',
    },
  },
];

const source = ($input.first() || {}).json || {};

const org_id = source.org_id ?? null;
const platform = source.platform ?? null;
const external_account_id = source.external_account_id ?? null;
const channel_access_token = source.channel_access_token ?? '';
const body = source.body || {};
const nowIso = new Date().toISOString();

function toIso(input) {
  if (input === null || input === undefined || input === '') return nowIso;
  const num = Number(input);
  if (!Number.isFinite(num)) return nowIso;
  const millis = num < 1000000000000 ? num * 1000 : num;
  const d = new Date(millis);
  return Number.isNaN(d.getTime()) ? nowIso : d.toISOString();
}

function makeBase() {
  return {
    org_id,
    platform,
    external_account_id,
    channel_access_token,
    SUPABASE_URL: source.SUPABASE_URL || '',
    META_GRAPH_VERSION: source.META_GRAPH_VERSION || '',
  };
}

const out = [];
const entry0 = Array.isArray(body.entry) ? (body.entry[0] || {}) : {};

if (platform === 'whatsapp') {
  const value = entry0?.changes?.[0]?.value || {};
  const messages = Array.isArray(value.messages) ? value.messages : [];
  const contacts = Array.isArray(value.contacts) ? value.contacts : [];

  const contactNames = {};
  for (const contact of contacts) {
    const waId = contact?.wa_id == null ? '' : String(contact.wa_id);
    if (waId) {
      contactNames[waId] = contact?.profile?.name ?? null;
    }
  }

  for (const message of messages) {
    if (!message || !message.from) continue;

    const base = {
      ...makeBase(),
      sender_external_id: String(message.from),
      sender_name: contactNames[String(message.from)] ?? null,
      created_at_iso: toIso(message.timestamp),
      provider_message_id: message.id || `wa-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`,
      raw_event: message,
    };

    if (message.type === 'text') {
      out.push({
        ...base,
        content_type: 'text',
        content_text: message.text?.body || '',
        media: null,
      });
      continue;
    }

    if (message.type === 'image') {
      out.push({
        ...base,
        content_type: 'image',
        content_text: message.image?.caption || '',
        media: {
          kind: 'image',
          mime_type: message.image?.mime_type || '',
          wa_media_id: message.image?.id || null,
          url: message.image?.url || null,
        },
      });
      continue;
    }

    if (message.type === 'audio') {
      out.push({
        ...base,
        content_type: 'audio',
        content_text: '',
        media: {
          kind: 'audio',
          mime_type: message.audio?.mime_type || '',
          wa_media_id: message.audio?.id || null,
          url: message.audio?.url || null,
        },
      });
      continue;
    }
  }
} else if (platform === 'page' || platform === 'instagram') {
  const events = Array.isArray(entry0.messaging) ? entry0.messaging : [];

  for (const event of events) {
    const msg = event?.message || {};
    const senderId = event?.sender?.id;

    if (!senderId) continue;
    if (msg.is_echo === true) continue;

    const base = {
      ...makeBase(),
      sender_external_id: String(senderId),
      sender_name: null,
      created_at_iso: toIso(event.timestamp),
      provider_message_id: msg.mid || String(event.timestamp || `meta-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`),
      raw_event: event,
    };

    if (typeof msg.text === 'string' && msg.text.length >= 0) {
      out.push({
        ...base,
        content_type: 'text',
        content_text: msg.text,
        media: null,
      });
      continue;
    }

    const attachments = Array.isArray(msg.attachments) ? msg.attachments : [];
    const firstSupported = attachments.find((att) => ['image', 'audio', 'video'].includes(att?.type));

    if (!firstSupported) continue;

    if (firstSupported.type === 'image') {
      out.push({
        ...base,
        content_type: 'image',
        content_text: '',
        media: {
          kind: 'image',
          mime_type: '',
          url: firstSupported?.payload?.url || null,
        },
      });
      continue;
    }

    if (firstSupported.type === 'audio' || firstSupported.type === 'video') {
      out.push({
        ...base,
        content_type: 'audio',
        content_text: '',
        media: {
          kind: 'audio',
          mime_type: '',
          url: firstSupported?.payload?.url || null,
        },
      });
      continue;
    }
  }
}

return out.map((item) => ({ json: item }));

function decodeBinaryToString(binaryEntry) {
  try {
    if (!binaryEntry || typeof binaryEntry.data !== 'string') return '';
    return Buffer.from(binaryEntry.data, 'base64').toString('utf8');
  } catch (e) {
    return '';
  }
}

const current = $input.first() || { json: {}, binary: {} };
const root = current.json || {};
const binary = current.binary || {};

// Your webhook data is nested inside current.json.headers
const requestData = root.headers || {};

const headers = requestData.headers || {};
const query = requestData.query || {};
const body = requestData.body || {};

let rawBodyString = '';

if (typeof requestData.rawBody === 'string') {
  rawBodyString = requestData.rawBody;
} else if (typeof requestData.rawBodyString === 'string') {
  rawBodyString = requestData.rawBodyString;
} else if (typeof body === 'string') {
  rawBodyString = body;
} else if (body && typeof body === 'object') {
  rawBodyString = JSON.stringify(body);
} else {
  for (const key of ['data', 'rawBody', 'body']) {
    rawBodyString = decodeBinaryToString(binary[key]);
    if (rawBodyString) break;
  }
}

// Since method is not reliably present in your input,
// detect verification by the presence of hub query params
const isVerifyRequest =
  query['hub.mode'] !== undefined ||
  query.hub_mode !== undefined ||
  query['hub.challenge'] !== undefined ||
  query.hub_challenge !== undefined ||
  query['hub.verify_token'] !== undefined ||
  query.hub_verify_token !== undefined;

if (isVerifyRequest) {
  return [
    {
      json: {
        route: 'verify',
        hub_mode: query['hub.mode'] ?? query.hub_mode ?? null,
        hub_verify_token: query['hub.verify_token'] ?? query.hub_verify_token ?? null,
        hub_challenge: query['hub.challenge'] ?? query.hub_challenge ?? null,
      },
    },
  ];
}

return [
  {
    json: {
      route: 'event',
      headers,
      body,
      rawBodyString,
    },
  },
];

const source = ($input.first() || {}).json || {};
const body = source.body || {};
const headers = source.headers || {};
const entry0 = Array.isArray(body.entry) ? (body.entry[0] || {}) : {};
const change0 = Array.isArray(entry0.changes) ? (entry0.changes[0] || {}) : {};
const value0 = change0.value || {};
const messaging0 = Array.isArray(entry0.messaging) ? entry0.messaging : [];

const constants = ($('Constants').all(0, $runIndex)[0] || {}).json || {};

let platform = null;
let external_account_id = null;

if (value0?.metadata?.phone_number_id) {
  platform = 'whatsapp';
  external_account_id = String(value0.metadata.phone_number_id);
} else {
  const firstMid = messaging0[0]?.message?.mid || '';
  const looksInstagram =
    body.object === 'instagram' ||
    headers['instagram-api-version'] ||
    headers['Instagram-API-Version'] ||
    /^aWdf/i.test(String(firstMid));

  if (looksInstagram && messaging0.length > 0) {
    platform = 'instagram';
    external_account_id = entry0.id == null ? null : String(entry0.id);
  } else if (body.object === 'page' && messaging0.length > 0) {
    platform = 'page';
    external_account_id = entry0.id == null ? null : String(entry0.id);
  } else if (looksInstagram) {
    platform = 'instagram';
    external_account_id = entry0.id == null ? null : String(entry0.id);
  } else {
    platform = body.object ? String(body.object) : null;
    external_account_id = entry0.id == null ? null : String(entry0.id);
  }
}

return [
  {
    json: {
      headers,
      body,
      rawBodyString: typeof source.rawBodyString === 'string' ? source.rawBodyString : '',
      platform,
      external_account_id,
      SUPABASE_URL: constants.SUPABASE_URL || '',
      META_GRAPH_VERSION: constants.META_GRAPH_VERSION || '',
    },
  },
];

const downloaded = $('Download Media Binary1').first() || { json: {}, binary: {} };
const computed = $('Compute Media Path1').first()?.json || {};
const upload = $('Upload Media to Supabase Storage1').first()?.json || {};

return [{
  json: {
    ...computed,
    media_bucket: computed.bucket || computed.media_bucket || 'inbox_media',
    media_path: upload.Key || computed.media_path || null,
  },
  binary: downloaded.binary,
}];

const current = $input.first() || { json: {} };
const transcriptSource = current.json || {};
const compute = $('Compute Media Path1').first()?.json || {};
const attach = $('Attach Media Storage Fields1').first()?.json || {};

const transcript =
  transcriptSource.text ??
  transcriptSource.transcript ??
  transcriptSource.data?.text ??
  transcriptSource.output ??
  '';

return [{
  json: {
    ...compute,
    ...attach,
    content_text: String(transcript || ''),
    transcript: String(transcript || ''),
  },
  binary: current.binary,
}];

const item = $input.first() || { json: {}, binary: {} };
const j = item.json || {};

const hasMedia = j.content_type === 'image' || j.content_type === 'audio';

const meta = {
  raw_event: j.raw_event ?? {},
  provider_message_id: j.provider_message_id ?? null,
  external_account_id: j.external_account_id ?? null,
  media: j.media ?? null,
  image_analysis: j.image_analysis ?? null,
  transcript: j.transcript ?? null,
  image_analysis_summary: j.image_analysis_summary ?? null,
  provider_debug: {
    download_url: j.download_url ?? null,
    wa_media_id: j.media?.wa_media_id ?? null,
    provider_url: j.media?.url ?? null,
  },
};

return [{
  json: {
    ...j,
    media_bucket: hasMedia ? (j.media_bucket || 'inbox_media') : null,
    media_path: hasMedia ? (j.media_path || null) : null,
    meta,
  },
  binary: item.binary,
}];

const inputs = $input.all();
const originals = $('PART2_IN').all(0, $runIndex);

function collectErrorBits(item) {
  const bits = [];
  if (!item) return bits;
  const sources = [item, item.json || {}, item.error || {}, item.json?.error || {}, item.json?.data || {}];
  for (const src of sources) {
    if (!src || typeof src !== 'object') continue;
    for (const [k, v] of Object.entries(src)) {
      if (v === undefined || v === null) continue;
      if (typeof v === 'object') {
        try { bits.push(JSON.stringify(v)); } catch (e) {}
      } else {
        bits.push(String(v));
      }
      if (/code|status|message|details|hint|error/i.test(k) && typeof v !== 'object') {
        bits.push(String(v));
      }
    }
  }
  return bits.join(' | ');
}

function isDuplicateLike(item) {
  const text = collectErrorBits(item).toLowerCase();
  const checks = [
    'duplicate',
    'already exists',
    'unique constraint',
    'violates unique constraint',
    '23505',
    '409',
    'conflict',
    'duplicate key value',
  ];
  return checks.some((c) => text.includes(c));
}

const out = [];

for (let i = 0; i < inputs.length; i++) {
  const current = inputs[i];
  const original = originals[i] || { json: {}, binary: {} };

  const hasError =
    !!current.error ||
    !!current.json?.error ||
    !!current.json?.statusCode ||
    !!current.json?.code ||
    (typeof current.json?.message === 'string' && /error/i.test(current.json.message));

  if (hasError) {
    if (isDuplicateLike(current)) {
      continue;
    }
    throw new Error(collectErrorBits(current) || 'Unknown Supabase error during dedupe insert');
  }

  out.push({
    json: { ...(original.json || {}) },
    binary: original.binary,
    pairedItem: i,
  });
}

return out;

const current = $input.first() || { json: {} };
const original = $('Dedupe Decision').first() || { json: {}, binary: {} };
const row = current.json || {};

if (!row.id) {
  throw new Error('Unable to resolve contact_id');
}

return [{
  json: {
    ...(original.json || {}),
    contact_id: row.id,
  },
