}

function excerpt(text, maxLen) {
  const clean = String(text || '').replace(/\s+/g, ' ').trim();
  if (!clean) return '';
  return clean.length > maxLen ? clean.slice(0, maxLen) + '…' : clean;
}

function hasArabic(text) {
  return /[\u0600-\u06FF]/.test(String(text || ''));
}

function normalizeDigits(value) {
  const map = {
    '٠': '0', '١': '1', '٢': '2', '٣': '3', '٤': '4', '٥': '5', '٦': '6', '٧': '7', '٨': '8', '٩': '9',
    '۰': '0', '۱': '1', '۲': '2', '۳': '3', '۴': '4', '۵': '5', '۶': '6', '۷': '7', '۸': '8', '۹': '9'
  };
  return String(value || '').replace(/[٠-٩۰-۹]/g, d => map[d] || d);
}

function uniqueList(values) {
  const seen = new Set();
  const out = [];
  for (const value of values) {
    const clean = String(value || '').trim();
    if (!clean || seen.has(clean)) continue;
    seen.add(clean);
    out.push(clean);
  }
  return out;
}

function extractPhoneNumbers(text) {
  const normalized = normalizeDigits(text);
  const matches = normalized.match(/(?:\+?\d[\d\s\-()]{7,}\d)/g) || [];
  return uniqueList(
    matches
      .map(v => v.replace(/[^0-9+]/g, ''))
      .filter(v => v.replace(/\D/g, '').length >= 8)
  );
}

function str(value) {
  return String(value ?? '').trim();
}

function hasValue(value) {
  return str(value) !== '';
}

function pickFirst() {
  for (const value of arguments) {
    if (hasValue(value)) return str(value);
  }
  return '';
}

function regexAny(text, patterns) {
  const value = normalizeDigits(String(text || '')).toLowerCase();
  return patterns.some((pattern) => pattern.test(value));
}

function normalizeSearchText(value) {
  return normalizeDigits(String(value || ''))
    .toLowerCase()
    .replace(/[^\w\u0600-\u06FF]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenizeSearch(value) {
  const normalized = normalizeSearchText(value);

  const stopWords = new Set([
    'the', 'and', 'or', 'for', 'with', 'from', 'this', 'that', 'what', 'how', 'much', 'price', 'cost',
    'في', 'من', 'على', 'عن', 'ده', 'دي', 'دا', 'ايه', 'إيه', 'هو', 'هي', 'هل', 'انا', 'أنا', 'انت',
    'حضرتك', 'يا', 'فندم', 'لو', 'عشان', 'الى', 'إلى', 'او', 'أو', 'و', 'بكام', 'كام', 'السعر'
  ]);

  return uniqueList(
    normalized
      .split(/\s+/)
      .map(v => v.trim())
      .filter(v => v.length >= 2)
      .filter(v => !stopWords.has(v))
      .filter(v => !/^\d+$/.test(v))
  ).slice(0, 80);
}

function scoreTextByTerms(text, terms) {
  const normalized = normalizeSearchText(text);
  if (!normalized || !terms.length) return 0;

  let score = 0;

  for (const term of terms) {
    if (!term) continue;
    if (normalized.includes(term)) score += term.length >= 5 ? 3 : 1;
  }

  return score;
}

function getEgyptNowParts(date = new Date()) {
  const timezone = 'Africa/Cairo';

  const formatter = new Intl.DateTimeFormat('en-GB-u-nu-latn', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
    hourCycle: 'h23'
  });

  const parts = formatter.formatToParts(date).reduce((acc, part) => {
    if (part.type !== 'literal') acc[part.type] = part.value;
    return acc;
  }, {});

  const weekday = new Intl.DateTimeFormat('en-GB', {
    timeZone: timezone,
    weekday: 'long'
  }).format(date);

  let offset = '+02:00';

  try {
    const offsetPart = new Intl.DateTimeFormat('en-GB-u-nu-latn', {
      timeZone: timezone,
      timeZoneName: 'shortOffset'
    })
      .formatToParts(date)
      .find(part => part.type === 'timeZoneName')?.value || '';

    const match = offsetPart.match(/GMT([+-])(\d{1,2})(?::?(\d{2}))?/i);

    if (match) {
      const sign = match[1];
      const hours = String(match[2]).padStart(2, '0');
      const minutes = String(match[3] || '00').padStart(2, '0');
      offset = `${sign}${hours}:${minutes}`;
    }
  } catch (e) {
    offset = '+02:00';
  }

  const datePart = `${parts.year}-${parts.month}-${parts.day}`;
  const timePart = `${parts.hour}:${parts.minute}:${parts.second}`;

  return {
    timezone,
    offset,
    date: datePart,
    time: timePart,
    datetime: `${datePart}T${timePart}${offset}`,
    weekday
  };
}

